document.addEventListener("DOMContentLoaded", () => {
    "use strict";

    const heroContainer = document.querySelector(".hero-container");
    const slides = document.querySelectorAll(".hero-slide");
    const nextBtn = document.querySelector(".slider-nav.next");

    if (!heroContainer || slides.length === 0) return;

    let current = 0;
    let autoInterval = null;
    const intervalTime = 10000; // 10 seconds

    const goToSlide = (index) => {
        // Remove active class from all slides
        slides.forEach(slide => slide.classList.remove("active"));

        // Wrap around logic
        if (index >= slides.length) index = 0;
        if (index < 0) index = slides.length - 1;

        // Add active class to new slide
        slides[index].classList.add("active");
        current = index;
    };

    const restartAuto = () => {
        if (autoInterval) clearInterval(autoInterval);
        autoInterval = setInterval(() => goToSlide(current + 1), intervalTime);
    };

    // Initialize first slide and start auto-timer
    goToSlide(0);
    restartAuto();

    // Next arrow click
    if (nextBtn) {
        nextBtn.addEventListener("click", () => {
            goToSlide(current + 1);
            restartAuto();
        });
    }

    // Keyboard support (Left/Right Arrows)
    document.addEventListener("keydown", (evt) => {
        // Prevent interfering with input fields
        if (["INPUT", "TEXTAREA", "SELECT"].includes(document.activeElement?.tagName || "")) return;

        if (evt.key === "ArrowLeft") {
            evt.preventDefault();
            goToSlide(current - 1);
            restartAuto();
        } else if (evt.key === "ArrowRight") {
            evt.preventDefault();
            goToSlide(current + 1);
            restartAuto();
        }
    });

    // Touch support for mobile (Slide Gestures)
    let touchStartX = 0;
    let touchEndX = 0;

    heroContainer.addEventListener("touchstart", (e) => {
        touchStartX = e.changedTouches[0].screenX;
    }, { passive: true });

    heroContainer.addEventListener("touchend", (e) => {
        touchEndX = e.changedTouches[0].screenX;
        handleSwipe();
    }, { passive: true });

    const handleSwipe = () => {
        const swipeThreshold = 50; // Minimum distance for a swipe
        const diff = touchStartX - touchEndX;

        if (Math.abs(diff) > swipeThreshold) {
            if (diff > 0) {
                // Swiped left -> Go to next slide
                goToSlide(current + 1);
            } else {
                // Swiped right -> Go to previous slide
                goToSlide(current - 1);
            }
            restartAuto();
        }
    };
});
